import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { addToCart } from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/fixUrl';
import s from './ProductCard.module.css';

const ProductCard = ({ id, title, price, discont_price, image }) => { 
  const dispatch = useDispatch();
  // Опционально: локальное состояние для демонстрации "Added"
  const [isAdded, setIsAdded] = useState(false); 

  const imageUrl = getImageUrl(image);

  // Определяем цены
  const originalPrice = price || 0;
  const finalPrice = discont_price !== null ? discont_price : originalPrice;

  const isDiscounted = discont_price !== null && originalPrice > discont_price;

  let discountPercent = 0;
  if (isDiscounted) {
    discountPercent = Math.round(((originalPrice - discont_price) / originalPrice) * 100);
  }

  // Функция обработки добавления в корзину
  const handleAddToCart = (e) => {
    e.preventDefault(); 
    e.stopPropagation(); 

    dispatch(addToCart({
      id,
      title,
      price: finalPrice, 
      image,
      count: 1 
    }));

    // Устанавливаем состояние "Added" на 2 секунды
    setIsAdded(true);
    setTimeout(() => {
        setIsAdded(false);
    }, 2000);
  };

  return (
    // Вся карточка - контейнер для эффекта наведения
    <div className={s.productCard}>
        {/* Ссылка обертывает все, кроме кнопки */}
        <Link to={`/products/${id}`} className={s.link}>

            <div className={s.imageWrapper}>
                <img src={imageUrl} alt={title} className={s.image} />

                {/* Бейдж скидки */}
                {isDiscounted && (
                    <div className={s.discountBadge}>
                        -{discountPercent}%
                    </div>
                )}
            </div>


            <div className={s.content}>
                <h3 className={s.title}>{title}</h3>

                <div className={s.priceContainer}>
                    {/* Крупная финальная цена */}
                    <p className={s.finalPrice}>
                        ${finalPrice.toFixed(2)}
                    </p>

                    {/* Зачеркнутая оригинальная цена */}
                    {isDiscounted && (
                        <p className={s.originalPrice}>
                            ${originalPrice.toFixed(2)}
                        </p>
                    )}
                </div>
            </div>
        </Link>

    </div>
  );
};

export default ProductCard;
